import React from "react";
import MasonryGrid from "./MasonryGrid";
import Wave from "../DecorationComponents/wavecircle.svg";



const Galeria=()=>{
    return(
    <section className="min-h-[100vh] py-[25vh] relative">

  {/* SVG derecha */}
  <div className="pointer-events-none absolute inset-0 -z-10 overflow-hidden">
    <img
      src={Wave}
      className="
        sticky
        top-1/2
        ml-auto
        right-[-40vw]
        -translate-y-1/2
        w-[80vw]
        max-w-[100vw]
      "
    />
  </div>

  {/* SVG izquierda */}
  <div className="pointer-events-none absolute inset-0 -z-10 overflow-hidden">
    <img
      src={Wave}
      className="
        sticky
        top-1/2
        left-[-40vw]
        -translate-y-1/2
        w-[80vw]
        max-w-[100vw]
      "
    />
  </div>

  {/* CONTENIDO */}
  <div className="text-center m-[5vh]">
    <h1 className="titulo-playfair font-semibold text-[#7D6239] text-[2rem]">
      ¿Te quedaste con ganas de ver más?
    </h1>

    <div className="h-[5px] w-[3rem] mx-auto rounded-full bg-gradient-to-r from-[#CC2329] to-[#F55809]" />
  </div>

  <div className="w-[50%] mx-auto">
    <MasonryGrid />
  </div>

</section>

    );
};

export default Galeria;
